#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int R, C; scanf("%d %d", &R, &C);
        char grid[101][101];
        for (int i = 0; i < R; ++i) {
            scanf("%s", grid[i]);
        }
        int found = 0;
        // check rows
        for (int i = 0; i < R && !found; ++i) {
            char row[101];
            for (int j = 0; j < C; ++j) row[j] = tolower(grid[i][j]);
            row[C] = '\0';
            if (strstr(row, "spoon")) found = 1;
        }
        // check columns
        for (int j = 0; j < C && !found; ++j) {
            char col[101];
            for (int i = 0; i < R; ++i) col[i] = tolower(grid[i][j]);
            col[R] = '\0';
            if (strstr(col, "spoon")) found = 1;
        }
        if (found) printf("There is a spoon!\n");
        else printf("There is indeed no spoon!\n");
    }
    return 0;
}

