        int R, C; cin >> R >> C;
        vector<string> grid(R);
        for(int i=0;i<R;++i) cin >> grid[i];
        bool found = false;
        // rows
        for(int i=0;i<R && !found;++i){
            string row = grid[i];
            for(char &ch: row) ch = tolower(ch);
            if(row.find("spoon") != string::npos) found = true;
        }
        // columns
        for(int j=0;j<C && !found;++j){
            string col; col.reserve(R);
            for(int i=0;i<R;++i) col.push_back(tolower(grid[i][j]));
            if(col.find("spoon") != string::npos) found = true;
        }
        if(found) cout << "There is a spoon!\n";
        else cout << "There is indeed no spoon!\n";
    }
    return 0;
}

