import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int R = Integer.parseInt(st.nextToken());
            int C = Integer.parseInt(st.nextToken());
            char[][] grid = new char[R][C];
            for (int i = 0; i < R; ++i) {
                String line = br.readLine();
                for (int j = 0; j < C; ++j) grid[i][j] = Character.toLowerCase(line.charAt(j));
            }
            boolean found = false;
            // rows
            for (int i = 0; i < R && !found; ++i) {
                for (int j = 0; j + 5 <= C; ++j) {
                    if (grid[i][j] == 's' && grid[i][j+1] == 'p' && grid[i][j+2] == 'o' && grid[i][j+3] == 'o' && grid[i][j+4] == 'n') {
                        found = true; break;
                    }
                }
            }
            // columns
            for (int j = 0; j < C && !found; ++j) {
                for (int i = 0; i + 5 <= R; ++i) {
                    if (grid[i][j] == 's' && grid[i+1][j] == 'p' && grid[i+2][j] == 'o' && grid[i+3][j] == 'o' && grid[i+4][j] == 'n') {
                        found = true; break;
                    }
                }
            }
            out.append(found ? "There is a spoon!" : "There is indeed no spoon!").append('\n');
        }
        System.out.print(out.toString());
    }
}

