#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().splitlines()
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        R, C = map(int, next(it).split())
        grid = [next(it).strip() for _ in range(R)]
        found = False
        # rows
        for row in grid:
            if 'spoon' in row.lower():
                found = True
                break
        # columns
        if not found:
            for c in range(C):
                col = ''.join(grid[r][c] for r in range(R)).lower()
                if 'spoon' in col:
                    found = True
                    break
        out_lines.append('There is a spoon!' if found else 'There is indeed no spoon!')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

